import React, { useState, useEffect } from "react";
import axios from "axios";

const Countries = () => {
  const [countries, setCountries] = useState([]);
  const [newCountry, setNewCountry] = useState({
    name: "",
    currency_code: "",
    language_code: "",
    region_code: "",
  });
  const [editingCountry, setEditingCountry] = useState(null);

  useEffect(() => {
    axios
      .get("/api/countries")
      .then((response) => setCountries(response.data))
      .catch((err) => console.error(err));
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewCountry({
      ...newCountry,
      [name]: value,
    });
  };

  const handleCreateCountry = (e) => {
    e.preventDefault();
    axios
      .post("/api/countries_create", newCountry)
      .then((response) => {
        setCountries([...countries, response.data]);
        resetForm();
      })
      .catch((err) => console.error(err));
  };

  const handleEditCountry = (country) => {
    setEditingCountry(country);
    setNewCountry(country);
  };

  const handleUpdateCountry = (e) => {
    e.preventDefault();
    axios
      .put(`/api/countries_put${editingCountry.id}`, newCountry)
      .then((response) => {
        setCountries(
          countries.map((country) =>
            country.id === editingCountry.id ? response.data : country
          )
        );
        resetForm();
      })
      .catch((err) => console.error(err));
  };

  const handleDeleteCountry = (id) => {
    axios
      .delete(`/api/countries_del${id}`)
      .then(() => setCountries(countries.filter((country) => country.id !== id)))
      .catch((err) => console.error(err));
  };

  const resetForm = () => {
    setEditingCountry(null);
    setNewCountry({
      name: "",
      currency_code: "",
      language_code: "",
      region_code: "",
    });
  };

  return (
    <div className="form-container">
      <div className="form-card">
        <h2>{editingCountry ? "Edit Country" : "Create Country"}</h2>
        <form onSubmit={editingCountry ? handleUpdateCountry : handleCreateCountry}>
          <div className="input-group">
            <label>Country Name</label>
            <input
              type="text"
              name="name"
              value={newCountry.name}
              placeholder="Enter country name"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Currency Code</label>
            <input
              type="text"
              name="currency_code"
              value={newCountry.currency_code}
              placeholder="Enter currency code"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Language Code</label>
            <input
              type="text"
              name="language_code"
              value={newCountry.language_code}
              placeholder="Enter language code"
              onChange={handleInputChange}
            />
          </div>
          <div className="input-group">
            <label>Region Code</label>
            <input
              type="text"
              name="region_code"
              value={newCountry.region_code}
              placeholder="Enter region code"
              onChange={handleInputChange}
            />
          </div>

          <button type="submit" className="submit-btn">
            {editingCountry ? "Update Country" : "Create Country"}
          </button>
        </form>
      </div>

      <div className="countries-table">
        <div style={{ overflowX: "auto" }}>
          <table>
            <thead>
              <tr>
                <th>Country Name</th>
                <th>Currency Code</th>
                <th>Language Code</th>
                <th>Region Code</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {countries.map((country) => (
                <tr key={country.id}>
                  <td>{country.name}</td>
                  <td>{country.currency_code}</td>
                  <td>{country.language_code}</td>
                  <td>{country.region_code}</td>
                  <td className="action-buttons">
                    <button
                      className="action-btn"
                      onClick={() => handleEditCountry(country)}
                    >
                      Edit
                    </button>
                    <button
                      className="action-btn"
                      onClick={() => handleDeleteCountry(country.id)}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Countries;
